import math

class Solution:
    def minEatingSpeed(self, piles: list[int], h: int) -> int:
        def canFinish(k):
            hours = 0
            for pile in piles:
                hours += math.ceil(pile / k)
            return hours <= h

        left, right = 1, max(piles)
        result = right
        while left <= right:
            mid = (left + right) // 2
            if canFinish(mid):
                result = mid         # mid works, try slower
                right = mid - 1
            else:
                left = mid + 1       # mid too slow, go faster
        return result

